<?php require_once '../../config/config.php'; requireAdmin(); if($_SERVER['REQUEST_METHOD']==='POST'){db()->prepare('INSERT INTO categories(name,slug) VALUES(?,?)')->execute([$_POST['name'],strtolower(trim(preg_replace('/\s+/','-',$_POST['name'])))]);} $rows=db()->query('SELECT * FROM categories')->fetchAll(PDO::FETCH_ASSOC); ?><h2>Categories</h2><form method="post"><input name="name" placeholder="Category"><button>Add</button></form><?php foreach($rows as $r) echo '<p>'.e($r['name']).'</p>'; ?>
